import{_ as a,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Paro de Emergencia","description":"","frontmatter":{},"headers":[],"relativePath":"es/safety/emergency-stop.md","filePath":"es/safety/emergency-stop.md"}'),n={name:"es/safety/emergency-stop.md"};function s(c,e,l,d,t,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="paro-de-emergencia" tabindex="-1">Paro de Emergencia <a class="header-anchor" href="#paro-de-emergencia" aria-label="Permalink to &quot;Paro de Emergencia&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Un paro de emergencia es una función de seguridad diseñada para detener inmediatamente una máquina o proceso en una situación peligrosa.</p><p>Típicamente se implementa mediante un dispositivo dedicado que, al activarse, elimina la energía o lleva el sistema a un estado seguro lo más rápido posible.</p><p>Los paros de emergencia son una parte crítica de los sistemas de seguridad industrial.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de un paro de emergencia es reducir el riesgo durante condiciones anormales o peligrosas.</p><p>Se utiliza para:</p><ul><li>Detener movimientos o procesos peligrosos</li><li>Proteger al personal de lesiones</li><li>Prevenir daños al equipo</li><li>Proporcionar una acción de seguridad rápida y accesible</li></ul><p>Está destinado a situaciones de emergencia, no a la operación normal.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Un sistema de paro de emergencia interrumpe los circuitos de control o de potencia para detener el sistema de forma segura.</p><h3 id="dispositivo-de-activacion" tabindex="-1">Dispositivo de activación <a class="header-anchor" href="#dispositivo-de-activacion" aria-label="Permalink to &quot;Dispositivo de activación&quot;">​</a></h3><p>El paro de emergencia suele ser un botón pulsador.</p><ul><li>Botón rojo con fondo amarillo</li><li>Mecanismo de enclavamiento que permanece activado al presionarse</li></ul><p>Debe ser fácilmente accesible para los operadores.</p><h3 id="circuito-de-seguridad" tabindex="-1">Circuito de seguridad <a class="header-anchor" href="#circuito-de-seguridad" aria-label="Permalink to &quot;Circuito de seguridad&quot;">​</a></h3><p>El paro de emergencia se conecta a un circuito de seguridad.</p><ul><li>Típicamente utiliza contactos normalmente cerrados</li><li>La apertura del circuito activa el paro</li></ul><p>Esto asegura un comportamiento a prueba de fallos.</p><h3 id="accion-de-paro" tabindex="-1">Acción de paro <a class="header-anchor" href="#accion-de-paro" aria-label="Permalink to &quot;Acción de paro&quot;">​</a></h3><p>Al activarse:</p><ul><li>Se elimina o controla de forma segura la potencia a los actuadores</li><li>El movimiento se detiene lo más rápido posible</li><li>El sistema entra en un estado seguro</li></ul><p>El método exacto de paro depende del diseño del sistema.</p><h3 id="funcion-de-reinicio" tabindex="-1">Función de reinicio <a class="header-anchor" href="#funcion-de-reinicio" aria-label="Permalink to &quot;Función de reinicio&quot;">​</a></h3><p>Después de la activación:</p><ul><li>El dispositivo debe reiniciarse manualmente</li><li>El arranque requiere una acción deliberada separada</li></ul><p>Esto previene el reinicio automático después de una falla.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los paros de emergencia se utilizan en todos los sistemas industriales.</p><p>Las aplicaciones típicas incluyen:</p><ul><li>Maquinaria y líneas de producción</li><li>Equipos accionados por motores</li><li>Sistemas automatizados</li><li>Plantas de proceso</li></ul><p>Son obligatorios donde existen peligros.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><p>Los paros de emergencia deben ser fácilmente accesibles y claramente visibles.</p><p>La función de paro debe ser confiable y a prueba de fallos.</p><p>El método de paro debe coincidir con el tipo de peligro.</p><p>La integración con los sistemas de seguridad debe diseñarse correctamente.</p><p>Deben seguirse las normas y regulaciones.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><p>Un error común es usar el paro de emergencia para paradas normales. Solo debe usarse en emergencias.</p><p>No omitir ni deshabilitar los circuitos de paro de emergencia.</p><p>Asegurar una ubicación adecuada para que los operadores puedan alcanzarlo rápidamente.</p><p>Probar la funcionalidad del paro de emergencia regularmente.</p><p>Verificar que el sistema permanezca en un estado seguro después de la activación.</p>',45)])])}const h=a(n,[["render",s]]);export{m as __pageData,h as default};
